import React, { useState, useEffect } from 'react';
import api from '../api/axiosConfig';
import { Terminal, Cpu, Zap, ShieldCheck, BarChart, Send, Loader2, Sparkles, MessageSquare } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import toast from 'react-hot-toast';

const Dashboard = () => {
  const [goal, setGoal] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);

  const handleGenerate = async (e) => {
    e.preventDefault();
    if (!goal) return toast.error("INITIALIZATION_FAILED: GOAL_NULL");
    
    setLoading(true);
    try {
      const res = await api.post('/portfolio/generate', { goal });
      setResult(res.data);
      toast.success("STRATEGY_SYNTHESIS_COMPLETE");
    } catch (err) {
      toast.error("AGENT_CONNECTION_ERROR");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={fullScreenWrapper}>
      {/* ── HEADER: SYSTEM METRICS ── */}
      <div style={topBar}>
        <div style={brandBox}>
          <Cpu size={18} color="var(--accent-primary)" />
          <span style={brandText}>FINIFY_STRATEGY_ENGINE_v4.2</span>
        </div>
        <div style={metricBox}>
          <div style={metricItem}><ActivityDot /> AGENT_CLUSTER: ONLINE</div>
          <div style={metricItem}>LATENCY: 24ms</div>
        </div>
      </div>

      <div style={mainGrid}>
        {/* ── LEFT PANEL: COMMAND INPUT ── */}
        <div style={leftPanel}>
          <div style={panelHeader}>
            <Terminal size={14} color="var(--accent-primary)" />
            <span style={panelLabel}>COMMAND_INPUT</span>
          </div>
          
          <form onSubmit={handleGenerate} style={formStyle}>
            <p style={inputDesc}>Define investment objective or market thesis:</p>
            <textarea
              style={textArea}
              placeholder="e.g., Build a high-growth portfolio of Indian tech stocks with low volatility..."
              value={goal}
              onChange={(e) => setGoal(e.target.value)}
            />
            <button 
              type="submit" 
              disabled={loading} 
              style={loading ? loadingBtn : actionBtn}
            >
              {loading ? <Loader2 className="spin" size={18} /> : <Send size={18} />}
              {loading ? 'SYNTHESIZING...' : 'INITIALIZE_AGENT_DEBATE'}
            </button>
          </form>

          <div style={hintBox}>
            <ShieldCheck size={16} color="var(--accent-primary)" />
            <p style={hintText}>Secure RAG-based analysis utilizing real-time yfinance streams.</p>
          </div>
        </div>

        {/* ── RIGHT PANEL: AGENTIC OUTPUT ── */}
        <div style={rightPanel}>
          {loading ? (
            <div style={loaderArea}>
              <Loader2 className="spin" size={40} color="var(--accent-primary)" />
              <p style={statusText}>AGENTS_ARE_DEBATING_MARKET_CONDITIONS...</p>
            </div>
          ) : result ? (
            <div className="reveal-node" style={outputContent}>
              {/* Summary Section */}
              <div style={resultSection}>
                <div style={sectionHeader}>
                  <Sparkles size={16} color="var(--accent-primary)" />
                  <span style={sectionLabel}>EXECUTIVE_SUMMARY</span>
                </div>
                <div className="markdown-vault">
                  <ReactMarkdown>{result.summary}</ReactMarkdown>
                </div>
              </div>

              {/* Rationale Section */}
              <div style={resultSection}>
                <div style={sectionHeader}>
                  <MessageSquare size={16} color="var(--accent-primary)" />
                  <span style={sectionLabel}>AGENTIC_RATIONALE</span>
                </div>
                <div className="markdown-vault">
                  <ReactMarkdown>{result.rationale}</ReactMarkdown>
                </div>
              </div>
            </div>
          ) : (
            <div style={idleArea}>
              <BarChart size={40} color="#1a1d23" />
              <p style={idleText}>AWAITING_COMMAND_INITIALIZATION</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

/* --- FULL SCREEN STYLES --- */
const fullScreenWrapper = { height: '100vh', width: '100vw', background: '#07080a', display: 'flex', flexDirection: 'column', overflow: 'hidden' };
const topBar = { height: '60px', borderBottom: '1px solid #1a1d23', display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '0 2rem', background: '#0a0b0e' };
const brandBox = { display: 'flex', alignItems: 'center', gap: '12px' };
const brandText = { fontSize: '0.8rem', fontWeight: 900, color: '#fff', letterSpacing: '0.1em', fontFamily: 'monospace' };
const metricBox = { display: 'flex', gap: '2rem' };
const metricItem = { fontSize: '0.6rem', color: '#666', fontWeight: 800, display: 'flex', alignItems: 'center', gap: '8px' };

const mainGrid = { display: 'grid', gridTemplateColumns: '400px 1fr', flex: 1, overflow: 'hidden' };

const leftPanel = { padding: '2.5rem', borderRight: '1px solid #1a1d23', display: 'flex', flexDirection: 'column', gap: '2rem', background: '#0a0b0e' };
const rightPanel = { padding: '0', overflowY: 'auto', background: 'radial-gradient(circle at top right, rgba(16,185,129,0.03) 0%, transparent 60%)' };

const panelHeader = { display: 'flex', alignItems: 'center', gap: '10px' };
const panelLabel = { fontSize: '0.7rem', fontWeight: 900, color: '#fff', letterSpacing: '0.2em' };

const formStyle = { display: 'flex', flexDirection: 'column', gap: '1.5rem' };
const inputDesc = { fontSize: '0.75rem', color: '#888', margin: 0 };
const textArea = { height: '200px', background: '#111318', border: '1px solid #1a1d23', borderRadius: '12px', padding: '1.2rem', color: '#fff', fontSize: '0.9rem', outline: 'none', transition: 'border 0.2s', resize: 'none' };

const actionBtn = { background: 'var(--accent-primary)', color: '#000', border: 'none', padding: '1rem', borderRadius: '12px', cursor: 'pointer', fontWeight: 900, fontSize: '0.8rem', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '12px' };
const loadingBtn = { ...actionBtn, opacity: 0.6, cursor: 'not-allowed' };

const hintBox = { display: 'flex', gap: '12px', padding: '1.2rem', background: 'rgba(255,255,255,0.02)', borderRadius: '12px', border: '1px solid #1a1d23' };
const hintText = { fontSize: '0.7rem', color: '#555', margin: 0, lineHeight: 1.5 };

const outputContent = { padding: '3rem' };
const resultSection = { marginBottom: '3rem' };
const sectionHeader = { display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '1.5rem', borderBottom: '1px solid #1a1d23', paddingBottom: '0.8rem' };
const sectionLabel = { fontSize: '0.65rem', fontWeight: 900, color: 'var(--accent-primary)', letterSpacing: '0.15em' };

const loaderArea = { height: '100%', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: '1.5rem' };
const statusText = { fontSize: '0.7rem', color: 'var(--accent-primary)', fontFamily: 'monospace', letterSpacing: '0.1em' };
const idleArea = { height: '100%', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', opacity: 0.2 };
const idleText = { marginTop: '1.5rem', fontSize: '0.75rem', fontWeight: 800, letterSpacing: '0.2em' };

const ActivityDot = () => (
  <span style={{ width: '6px', height: '6px', background: '#10b981', borderRadius: '50%', boxShadow: '0 0 8px #10b981' }} />
);

export default Dashboard;
